input.content:
#!/usr/bin/env bash

BRAVE_DIR="$HOME/.config/BraveSoftware/Brave-Browser/Default"
REPO_DIR="$(dirname "$0")"

backup() {
    cp "$BRAVE_DIR/Bookmarks" "$REPO_DIR/Bookmarks"
    echo "Backed up Bookmarks"
    cd "$REPO_DIR" && git add Bookmarks && git commit -m "brave: update bookmarks" && git push
}

restore() {
    cp "$REPO_DIR/Bookmarks" "$BRAVE_DIR/Bookmarks"
    echo "Restored Bookmarks"
}

case "$1" in
    backup)  backup ;;
    restore) restore ;;
    *) echo "Usage: $0 [backup|restore]" ;;
esac

